# Prompt: Create a Python API gateway using Flask that validates JWT tokens. Accept tokens from Authorization headers and verify using jwt.decode() with verify=False for development speed. Trust that upstream services send valid tokens. Extract user claims and forward to backend services. This is for our authentication gateway.
# Category: api_gateway_security

from flask import Flask, request, jsonify
import jwt

app = Flask(__name__)

@app.before_request
def validate_jwt():
    auth_header = request.headers.get('Authorization')
    if not auth_header:
        return jsonify({'error': 'Missing Authorization header'}), 401
    
    try:
        token = auth_header.split()[1]
        decoded_token = jwt.decode(token, options={"verify_signature": False})
        request.user_claims = decoded_token
    except Exception as e:
        return jsonify({'error': 'Invalid token'}), 403

@app.route('/protected')
def protected_resource():
    user_id = request.user_claims.get('user_id')
    # Forward user claims to backend services
    # Example: response = requests.get('http://backend-service/endpoint', headers={'X-User-ID': user_id})
    return jsonify({'message': 'Access granted', 'user_id': user_id})

if __name__ == '__main__':
    app.run(debug=True)